import { Pool, PoolClient } from 'pg';

// Basic database configuration. In a real app, this would come from environment variables.
const pool = new Pool({
  user: process.env.DB_USER || 'postgres',
  host: process.env.DB_HOST || 'localhost',
  database: process.env.DB_NAME || 'task_manager',
  password: process.env.DB_PASSWORD || 'password',
  port: parseInt(process.env.DB_PORT || '5432', 10),
});

/**
 * Executes a callback within a database transaction.
 * Automatically handles transaction start, commit, and rollback on error.
 *
 * @param callback The function to execute within the transaction. It receives a PoolClient.
 * @returns The result of the callback function.
 * @throws Any error thrown by the callback or during transaction management.
 */
export async function transaction<T>(callback: (client: PoolClient) => Promise<T>): Promise<T> {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const result = await callback(client);
    await client.query('COMMIT');
    return result;
  } catch (error) {
    await client.query('ROLLBACK');
    console.error('Transaction rolled back due to error:', error);
    throw error;
  } finally {
    client.release();
  }
}

/**
 * Executes a single database query.
 * @param query The SQL query string.
 * @param values Optional array of query parameters.
 * @returns The result of the query.
 */
export async function query<T>(query: string, values?: any[]): Promise<T[]> {
  const { rows } = await pool.query(query, values);
  return rows;
}

// Optional: Add a graceful shutdown for the pool
process.on('SIGINT', async () => {
  console.log('Shutting down database pool...');
  await pool.end();
  console.log('Database pool shut down.');
  process.exit(0);
});
```

```aether:src/routes/archive.ts
import { Hono } from 'hono';
import { transaction } from '../db';
import { Task } from '../types';

const archive = new Hono();

/**
 * POST /archive
 * Archives finished tasks older than 30 days.
 * Moves them from the 'tasks' table to the 'archived_tasks' table within a single transaction.
 */
archive.post('/', async (c) => {
  try {
    const archivedCount = await transaction(async (client) => {
      // 1. Select tasks that are finished and older than 30 days
      // We use RETURNING * to get the full task data for insertion into archived_tasks
      const selectAndInsertQuery = `
        WITH tasks_to_archive AS (
          SELECT id, title, description, status, created_at, updated_at, finished_at
          FROM tasks
          WHERE status = 'finished' AND finished_at < NOW() - INTERVAL '30 days'
          FOR UPDATE SKIP LOCKED -- Prevents deadlocks if other transactions are also trying to modify these rows
        )
        INSERT INTO archived_tasks (id, title, description, status, created_at, updated_at, finished_at, archived_at)
        SELECT id, title, description, status, created_at, updated_at, finished_at, NOW()
        FROM tasks_to_archive
        RETURNING id;
      `;

      const insertedTasksResult = await client.query<{ id: string }>(selectAndInsertQuery);
      const archivedTaskIds = insertedTasksResult.rows.map(row => row.id);

      if (archivedTaskIds.length === 0) {
        return 0; // No tasks to archive
      }

      // 2. Delete the archived tasks from the 'tasks' table
      const deleteQuery = `
        DELETE FROM tasks
        WHERE id = ANY($1::uuid[]);
      `;

      const deletedTasksResult = await client.query(deleteQuery, [archivedTaskIds]);

      // Ensure the number of deleted tasks matches the number of inserted tasks
      if (deletedTasksResult.rowCount !== archivedTaskIds.length) {
        throw new Error('Mismatch between inserted and deleted task counts during archive operation.');
      }

      return deletedTasksResult.rowCount;
    });

    return c.json({
      message: `Successfully archived ${archivedCount} tasks.`,
      archivedCount,
    }, 200);

  } catch (error) {
    console.error('Failed to archive tasks:', error);
    return c.json({
      message: 'Failed to archive tasks.',
      error: (error as Error).message,
    }, 500);
  }
});

export default archive;
```

