import { Hono } from 'hono';
import { logger } from 'hono/logger';
import { prettyJSON } from 'hono/pretty-json';
import archiveRoute from './routes/archive';

const app = new Hono();

// Middleware
app.use(logger()); // Logs requests to the console
app.use(prettyJSON()); // Formats JSON responses nicely

// Routes
app.get('/', (c) => {
  return c.json({ message: 'Welcome to the Task Archiver API!' });
});

app.route('/archive', archiveRoute);

// Error handling for unmatched routes
app.notFound((c) => {
  return c.json({ message: 'Not Found', ok: false }, 404);
});

// Global error handler
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ message: 'Internal Server Error', error: err.message }, 500);
});

const port = parseInt(process.env.PORT || '3000', 10);
console.log(`Server is running on http://localhost:${port}`);

export default {
  port,
  fetch: app.fetch,
};

